                                                        <div className="flex justify-center">
                                                            {item.status === 'PENDENTE' ? (
                                                                !isActive ? (
                                                                    <button 
                                                                        onClick={() => handleStart(activeBank.bankId, item.id)}
                                                                        className="px-4 py-1.5 bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300 rounded-full text-[9px] font-black uppercase tracking-widest shadow-sm hover:bg-brand-blue hover:text-white transition-all active:scale-95"
                                                                    >
                                                                        Iniciar
                                                                    </button>
                                                                ) : (
                                                                    <button 
                                                                        onClick={() => handleConfirm(activeBank.bankId, item.id)}
                                                                        className="px-4 py-1.5 bg-emerald-600 text-white rounded-full text-[9px] font-black uppercase tracking-widest shadow-lg shadow-emerald-500/20 hover:bg-emerald-700 transition-all active:scale-95 flex items-center gap-1.5"
                                                                    >
                                                                        <CheckCircleIcon className="w-3 h-3" />
                                                                        Confirmar
                                                                    </button>
                                                                )
                                                            ) : (
                                                                <div className="flex items-center gap-1 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase border border-emerald-100 dark:bg-emerald-900/30">
                                                                    <CheckCircleIcon className="w-3 h-3" />
                                                                    Lançado
                                                                </div>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })
                                    ) : (
                                        <tr>
                                            <td colSpan={5} className="py-20 text-center text-slate-400">
                                                <MagnifyingGlassIcon className="w-10 h-10 mx-auto mb-3 opacity-10" />
                                                <p className="text-xs font-bold uppercase tracking-widest">Nenhum item corresponde à busca.</p>
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-slate-400">
                         <ClockIcon className="w-12 h-12 mb-4 opacity-10" />
                         <p className="text-xs font-bold uppercase tracking-widest">
                             {bancos.length === 0 ? 'Nenhum extrato ativo para lançamento.' : 'Selecione um banco para visualizar os itens.'}
                         </p>
                    </div>
                )}
            </div>
        </div>
    );
};
